import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from 'react-query';
import { Toaster } from 'react-hot-toast';
import { AuthProvider } from './contexts/AuthContext';
import { ThemeProvider } from './contexts/ThemeContext';
import Layout from './components/Layout/Layout';
import ProtectedRoute from './components/Auth/ProtectedRoute';
import { Helmet } from 'react-helmet-async';

// Pages
import HomePage from './pages/HomePage';
import LoginPage from './pages/Auth/LoginPage';
import RegisterPage from './pages/Auth/RegisterPage';
import VideoDetailPage from './pages/Video/VideoDetailPage';
import DashboardPage from './pages/Dashboard/DashboardPage';
import NotFoundPage from './pages/NotFoundPage';

// Create a client
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: 1,
      refetchOnWindowFocus: false,
    },
  },
});

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <ThemeProvider>
        <AuthProvider>
          <Router>
            <div className="App">
              <Helmet>
                <title>EroStream - Premium Adult Content Platform</title>
                <meta name="description" content="EroStream is a premium adult content platform for creators and viewers. Share, discover, and monetize adult content safely and securely." />
                <meta name="keywords" content="adult content, video platform, creator monetization, adult entertainment" />
                <meta property="og:title" content="EroStream - Premium Adult Content Platform" />
                <meta property="og:description" content="Share, discover, and monetize adult content safely and securely." />
                <meta property="og:type" content="website" />
                <meta name="robots" content="noindex, nofollow" />
              </Helmet>

              <Routes>
                {/* Public routes */}
                <Route path="/" element={<Layout><HomePage /></Layout>} />
                <Route path="/login" element={<LoginPage />} />
                <Route path="/register" element={<RegisterPage />} />
                <Route path="/video/:videoId" element={<Layout><VideoDetailPage /></Layout>} />

                {/* Protected routes */}
                <Route path="/dashboard" element={
                  <ProtectedRoute>
                    <Layout><DashboardPage /></Layout>
                  </ProtectedRoute>
                } />

                {/* 404 route */}
                <Route path="*" element={<NotFoundPage />} />
              </Routes>

              <Toaster
                position="top-right"
                toastOptions={{
                  duration: 4000,
                  style: {
                    background: '#363636',
                    color: '#fff',
                  },
                  success: {
                    duration: 3000,
                    iconTheme: {
                      primary: '#10B981',
                      secondary: '#fff',
                    },
                  },
                  error: {
                    duration: 5000,
                    iconTheme: {
                      primary: '#EF4444',
                      secondary: '#fff',
                    },
                  },
                }}
              />
            </div>
          </Router>
        </AuthProvider>
      </ThemeProvider>
    </QueryClientProvider>
  );
}

export default App;
